3	function isNeighbor([ax, ay]: Cell, [bx, by]: Cell): boolean {
4	  const dx = Math.abs(ax - bx);
5	  const dy = Math.abs(ay - by);
6	  return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
7	}
8	
9	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
10	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
11	}
12	
13	function survives(neighbors: number): boolean {
14	  return neighbors === 2 || neighbors === 3;
15	}
16	
17	function isLive(cell: Cell, cells: Cell[]): boolean {
18	  return cells.some(([x, y]) => x === cell[0] && y === cell[1]);
19	}
20	
21	function candidateDeadCells(cells: Cell[]): Cell[] {
22	  const candidates: Cell[] = [];
23	  const seen = new Set<string>();
24	  for (const [x, y] of cells) {
25	    for (let dx = -1; dx <= 1; dx++) {
26	      for (let dy = -1; dy <= 1; dy++) {
27	        if (dx === 0 && dy === 0) continue;
28	        const nx = x + dx;
29	        const ny = y + dy;
30	        const key = `${nx},${ny}`;
31	        if (!seen.has(key) && !isLive([nx, ny], cells)) {
32	          seen.add(key);
33	          candidates.push([nx, ny]);
34	        }
35	      }
36	    }
37	  }
38	  return candidates;
39	}
40	
41	export function nextGeneration(cells: Cell[]): Cell[] {
42	  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
43	  const births = candidateDeadCells(cells).filter((cell) => countLiveNeighbors(cell, cells) === 3);
44	  return [...survivors, ...births];
45	}
