11	  it("should kill both cells in a pair with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable as a still life (survival with 3 neighbors)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
21	    // Center cell (1,1) has 4 live neighbors (corners) → dies from overpopulation
